/**
 * Minimal XLSX writer with native Excel line chart.
 * OOXML structure validated against openpyxl reference output.
 *
 * Set ws['!chart'] = { dataRows: N, sheetName: 'Captures' } to embed a
 * native line chart (Heap Used + Heap Total vs Timestamp) into that sheet.
 */
var XLSX = (function () {
  'use strict';

  // ── Address helpers ───────────────────────────────────────────────────────
  function encode_cell(c) {
    var col = '', n = c.c;
    do { col = String.fromCharCode(65 + (n % 26)) + col; n = Math.floor(n / 26) - 1; } while (n >= 0);
    return col + (c.r + 1);
  }
  function decode_range(s) {
    var p = s.split(':');
    function dc(a) { var v = 0; for (var i = 0; i < a.length; i++) if (a[i] >= 'A') v = v * 26 + a.charCodeAt(i) - 64; return v - 1; }
    function dr(a) { return parseInt(a.replace(/[A-Z]/g, '')) - 1; }
    var m = p[0].match(/([A-Z]+)(\d+)/), m2 = (p[1] || p[0]).match(/([A-Z]+)(\d+)/);
    return { s: { c: dc(m[1]), r: dr(m[2]) }, e: { c: dc(m2[1]), r: dr(m2[2]) } };
  }

  // ── Book / sheet helpers ──────────────────────────────────────────────────
  function book_new() { return { SheetNames: [], Sheets: {} }; }
  function book_append_sheet(wb, ws, name) { wb.SheetNames.push(name); wb.Sheets[name] = ws; }

  function json_to_sheet(data) {
    if (!data || !data.length) return { '!ref': 'A1' };
    var ws = {}, keys = Object.keys(data[0]);
    keys.forEach(function (k, c) { ws[encode_cell({ r: 0, c: c })] = { v: k, t: 's' }; });
    data.forEach(function (row, r) {
      keys.forEach(function (k, c) {
        var v = row[k]; if (v == null) return;
        ws[encode_cell({ r: r + 1, c: c })] = { v: v, t: typeof v === 'number' ? 'n' : 's' };
      });
    });
    ws['!ref'] = 'A1:' + encode_cell({ r: data.length, c: keys.length - 1 });
    ws['!cols'] = [];
    return ws;
  }

  function aoa_to_sheet(data) {
    var ws = {}, maxC = 0;
    data.forEach(function (row, r) {
      row.forEach(function (v, c) {
        if (c > maxC) maxC = c;
        if (v == null || v === '') return;
        ws[encode_cell({ r: r, c: c })] = { v: v, t: typeof v === 'number' ? 'n' : 's' };
      });
    });
    ws['!ref'] = 'A1:' + encode_cell({ r: data.length - 1, c: maxC });
    ws['!cols'] = [];
    return ws;
  }

  function escXml(s) {
    return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&apos;');
  }

  // ── OOXML part builders ───────────────────────────────────────────────────

  // ── Chart XML helpers ─────────────────────────────────────────────────────
  var _a = 'xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"';

  function _ser(idx, hdrRef, catRef, valRef) {
    return '<ser>' +
      '<idx val="' + idx + '"/><order val="' + idx + '"/>' +
      '<tx><strRef><f>' + hdrRef + '</f></strRef></tx>' +
      '<spPr><a:ln ' + _a + '><a:prstDash val="solid"/></a:ln></spPr>' +
      '<marker><symbol val="none"/>' +
        '<spPr><a:ln ' + _a + '><a:prstDash val="solid"/></a:ln></spPr>' +
      '</marker>' +
      '<cat><strRef><f>' + catRef + '</f></strRef></cat>' +
      '<val><numRef><f>' + valRef + '</f></numRef></val>' +
      '<smooth val="0"/>' +
    '</ser>';
  }

  function _axTitle(text) {
    return '<title><tx><rich>' +
      '<a:bodyPr ' + _a + '/>' +
      '<a:p ' + _a + '><a:pPr><a:defRPr/></a:pPr><a:r><a:t>' + text + '</a:t></a:r></a:p>' +
    '</rich></tx></title>';
  }

  function _chartTitle(text) {
    return '<title><tx><rich>' +
      '<a:bodyPr ' + _a + '/>' +
      '<a:p ' + _a + '><a:pPr><a:defRPr/></a:pPr>' +
        '<a:r><a:t>' + text + '</a:t></a:r>' +
      '</a:p>' +
    '</rich></tx></title>';
  }

  function _axes(catAxId, valAxId, yLabel) {
    return '' +
      '<catAx>' +
        '<axId val="' + catAxId + '"/>' +
        '<scaling><orientation val="minMax"/></scaling>' +
        '<axPos val="b"/>' +
        '<majorTickMark val="none"/><minorTickMark val="none"/>' +
        '<tickLblPos val="nextTo"/>' +
        '<crossAx val="' + valAxId + '"/>' +
        '<auto val="1"/>' +
        '<lblOffset val="100"/>' +
      '</catAx>' +
      '<valAx>' +
        '<axId val="' + valAxId + '"/>' +
        '<scaling><orientation val="minMax"/></scaling>' +
        '<axPos val="l"/>' +
        '<majorGridlines/>' +
        _axTitle(yLabel) +
        '<majorTickMark val="none"/><minorTickMark val="none"/>' +
        '<tickLblPos val="nextTo"/>' +
        '<crossAx val="' + catAxId + '"/>' +
      '</valAx>';
  }

  function _wrapChart(title, plotAreaContent) {
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
    '<chartSpace xmlns="http://schemas.openxmlformats.org/drawingml/2006/chart">' +
      '<style val="10"/>' +
      '<chart>' +
        _chartTitle(title) +
        '<plotArea>' + plotAreaContent + '</plotArea>' +
        '<legend><legendPos val="b"/></legend>' +
        '<plotVisOnly val="1"/>' +
        '<dispBlanksAs val="gap"/>' +
      '</chart>' +
    '</chartSpace>';
  }

  // Chart 1: Total Memory (MB) — Quick Layout 7
  // Quick Layout 7: title at top, plot area shrunk to leave room for data table,
  // data table with legend keys shown below the chart (replaces separate legend).
  function chartXmlMemory(dataRows, sheetName) {
    var sn = "'" + sheetName + "'";
    var last = dataRows + 1;
    var catRef = sn + '!$A$2:$A$' + last;
    var memRef = sn + '!$B$2:$B$' + last;
    var plotArea =
      // Manual layout: leave ~30% height at bottom for the data table
      '<layout><manLayout>' +
        '<layoutTarget val="inner"/>' +
        '<xMode val="factor"/><yMode val="factor"/>' +
        '<x val="0.08"/><y val="0.08"/><w val="0.86"/><h val="0.58"/>' +
      '</manLayout></layout>' +
      '<lineChart>' +
        '<grouping val="standard"/>' +
        '<varyColors val="0"/>' +
        _ser(0, sn + '!$B$1', catRef, memRef) +
        '<axId val="10"/><axId val="100"/>' +
      '</lineChart>' +
      _axes(10, 100, 'MB');
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
    '<chartSpace xmlns="http://schemas.openxmlformats.org/drawingml/2006/chart">' +
      '<style val="10"/>' +
      '<chart>' +
        _chartTitle('Total Memory Over Time') +
        '<plotArea>' + plotArea + '</plotArea>' +
        // Quick Layout 7: data table with series color keys, no separate legend
        '<dTable>' +
          '<showHorzBorder val="1"/>' +
          '<showVertBorder val="1"/>' +
          '<showOutline val="1"/>' +
          '<showKeys val="1"/>' +
        '</dTable>' +
        '<plotVisOnly val="1"/>' +
        '<dispBlanksAs val="gap"/>' +
      '</chart>' +
    '</chartSpace>';
  }

  // Chart 2: CPU Usage (%) — CPU Data sheet (A=Timestamp, B=CPU %)
  function chartXmlCpu(dataRows, sheetName) {
    var sn = "'" + sheetName + "'";
    var last = dataRows + 1;
    var catRef = sn + '!$A$2:$A$' + last;
    var cpuRef = sn + '!$B$2:$B$' + last;
    return _wrapChart('CPU Usage Over Time',
      '<lineChart>' +
        '<grouping val="standard"/>' +
        '<varyColors val="0"/>' +
        _ser(0, sn + '!$B$1', catRef, cpuRef) +
        '<axId val="10"/><axId val="100"/>' +
      '</lineChart>' +
      _axes(10, 100, '%')
    );
  }

  // drawing1.xml — uses oneCellAnchor + default namespace (no xdr: prefix)
  // Chart anchored starting at row 12 (0-indexed), col 0; size 9000000 x 5400000 EMU
  function drawingXml(anchorRow) {
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
    '<wsDr xmlns="http://schemas.openxmlformats.org/drawingml/2006/spreadsheetDrawing">' +
      '<oneCellAnchor>' +
        '<from><col>0</col><colOff>0</colOff><row>' + anchorRow + '</row><rowOff>0</rowOff></from>' +
        '<ext cx="9000000" cy="5400000"/>' +
        '<graphicFrame>' +
          '<nvGraphicFramePr>' +
            '<cNvPr id="1" name="Memory Chart"/>' +
            '<cNvGraphicFramePr/>' +
          '</nvGraphicFramePr>' +
          '<xfrm/>' +
          '<a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main">' +
            '<a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/chart">' +
              '<c:chart xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart" ' +
                       'xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" ' +
                       'r:id="rId1"/>' +
            '</a:graphicData>' +
          '</a:graphic>' +
        '</graphicFrame>' +
        '<clientData/>' +
      '</oneCellAnchor>' +
    '</wsDr>';
  }

  // ── Main builder ──────────────────────────────────────────────────────────
  function buildZip(wb) {
    var enc = new TextEncoder();
    var sheets = wb.SheetNames.map(function (n, i) { return { name: n, ws: wb.Sheets[n], id: i + 1 }; });
    var chartSheets = sheets.filter(function (sh) { return !!sh.ws['!chart']; });

    // Global shared strings
    var gSS = [], gMap = {};
    function addSS(v) { var s = String(v); if (gMap[s] == null) { gMap[s] = gSS.length; gSS.push(s); } return gMap[s]; }

    // Build worksheet XML
    var sheetsXml = sheets.map(function (sh) {
      var ws = sh.ws, hasChart = !!ws['!chart'];
      if (!ws['!ref']) return '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"><sheetData/></worksheet>';

      var range = decode_range(ws['!ref']), rMap = {};
      Object.keys(ws).forEach(function (addr) {
        if (addr[0] === '!') return;
        var m = addr.match(/([A-Z]+)(\d+)/); if (!m) return;
        var r = parseInt(m[2]) - 1;
        if (!rMap[r]) rMap[r] = [];
        rMap[r].push({ addr: addr, cell: ws[addr], c: decode_range(addr + ':' + addr).s.c });
      });

      var colsXml = '';
      if (ws['!cols'] && ws['!cols'].length) {
        colsXml = '<cols>' + ws['!cols'].map(function (col, i) {
          return col && col.wch ? '<col min="' + (i+1) + '" max="' + (i+1) + '" width="' + col.wch + '" customWidth="1"/>' : '';
        }).join('') + '</cols>';
      }

      var sdXml = '<sheetData>';
      for (var r = range.s.r; r <= range.e.r; r++) {
        if (!rMap[r]) continue;
        sdXml += '<row r="' + (r+1) + '">';
        rMap[r].sort(function (a, b) { return a.c - b.c; }).forEach(function (item) {
          var cell = item.cell, addr = item.addr;
          sdXml += cell.t === 'n'
            ? '<c r="' + addr + '" t="n"><v>' + (cell.v == null ? 0 : cell.v) + '</v></c>'
            : '<c r="' + addr + '" t="s"><v>' + addSS(cell.v == null ? '' : cell.v) + '</v></c>';
        });
        sdXml += '</row>';
      }
      sdXml += '</sheetData>';

      var freeze = ws['!freeze']
        ? '<sheetViews><sheetView workbookViewId="0"><pane ySplit="1" topLeftCell="A2" activePane="bottomLeft" state="frozen"/></sheetView></sheetViews>'
        : '';

      // drawing tag must be after sheetData; xmlns:r on <worksheet>
      var rootNs = 'xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"';
      if (hasChart) rootNs += ' xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"';
      var drawTag = hasChart ? '<drawing r:id="rId1"/>' : '';

      return '<worksheet ' + rootNs + '>' + freeze + colsXml + sdXml + drawTag + '</worksheet>';
    });

    // Shared strings XML
    var ssXml = '<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" count="' + gSS.length + '" uniqueCount="' + gSS.length + '">' +
      gSS.map(function (s) { return '<si><t xml:space="preserve">' + escXml(s) + '</t></si>'; }).join('') + '</sst>';

    // workbook.xml
    var wbXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" ' +
               'xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">' +
      '<sheets>' + sheets.map(function (sh) {
        return '<sheet name="' + escXml(sh.name) + '" sheetId="' + sh.id + '" r:id="rId' + sh.id + '"/>';
      }).join('') + '</sheets>' +
      '</workbook>';

    // xl/_rels/workbook.xml.rels
    var wbRels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">' +
      sheets.map(function (sh) {
        return '<Relationship Id="rId' + sh.id + '" ' +
          'Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" ' +
          'Target="worksheets/sheet' + sh.id + '.xml"/>';
      }).join('') +
      '<Relationship Id="rId' + (sheets.length + 1) + '" ' +
        'Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/sharedStrings" ' +
        'Target="sharedStrings.xml"/>' +
      '</Relationships>';

    // [Content_Types].xml
    var ct = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">' +
      '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>' +
      '<Default Extension="xml" ContentType="application/xml"/>' +
      '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>' +
      sheets.map(function (sh) {
        return '<Override PartName="/xl/worksheets/sheet' + sh.id + '.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>';
      }).join('') +
      chartSheets.map(function (sh) {
        return '<Override PartName="/xl/drawings/drawing' + sh.id + '.xml" ContentType="application/vnd.openxmlformats-officedocument.drawing+xml"/>' +
               '<Override PartName="/xl/charts/chart' + sh.id + '.xml" ContentType="application/vnd.openxmlformats-officedocument.drawingml.chart+xml"/>';
      }).join('') +
      '<Override PartName="/xl/sharedStrings.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sharedStrings+xml"/>' +
      '</Types>';

    // _rels/.rels
    var rootRels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">' +
      '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>' +
      '</Relationships>';

    // Assemble file map
    var files = {};
    var T = function (path, xml) { files[path] = enc.encode(xml); };

    T('[Content_Types].xml', ct);
    T('_rels/.rels', rootRels);
    T('xl/workbook.xml', wbXml);
    T('xl/_rels/workbook.xml.rels', wbRels);
    T('xl/sharedStrings.xml', ssXml);
    sheets.forEach(function (sh, i) {
      T('xl/worksheets/sheet' + sh.id + '.xml', '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' + sheetsXml[i]);
    });

    // Chart sheets: sheet rels → drawing, drawing XML, drawing rels → chart, chart XML
    chartSheets.forEach(function (sh) {
      var cfg = sh.ws['!chart'];
      var anchorRow = cfg.dataRows + 2; // place chart 2 rows below last data row

      // sheet rels → drawing (absolute target path, as openpyxl uses)
      T('xl/worksheets/_rels/sheet' + sh.id + '.xml.rels',
        '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
        '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">' +
        '<Relationship Id="rId1" ' +
          'Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing" ' +
          'Target="/xl/drawings/drawing' + sh.id + '.xml"/>' +
        '</Relationships>');

      // drawing XML
      T('xl/drawings/drawing' + sh.id + '.xml', drawingXml(anchorRow));

      // drawing rels → chart (absolute target path)
      T('xl/drawings/_rels/drawing' + sh.id + '.xml.rels',
        '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
        '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">' +
        '<Relationship Id="rId1" ' +
          'Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/chart" ' +
          'Target="/xl/charts/chart' + sh.id + '.xml"/>' +
        '</Relationships>');

      // chart XML — dispatch to the correct builder based on chartType
      var xmlFn = cfg.chartType === 'cpu' ? chartXmlCpu : chartXmlMemory;
      T('xl/charts/chart' + sh.id + '.xml', xmlFn(cfg.dataRows, cfg.sheetName));
    });

    return zipBuffer(files);
  }

  // ── Pure-JS ZIP (store) ───────────────────────────────────────────────────
  function zipBuffer(files) {
    var entries = [], dirs = [], off = 0;
    Object.keys(files).forEach(function (name) {
      var enc2 = new TextEncoder();
      var nb = enc2.encode(name);
      var data = files[name]; // Uint8Array
      var crc = crc32b(data);
      var lh = lhdr(nb, data.byteLength, crc);
      entries.push(lh); entries.push(data);
      dirs.push(cdir(nb, data.byteLength, crc, off));
      off += lh.byteLength + data.byteLength;
    });
    var cdSz = dirs.reduce(function (s, b) { return s + b.byteLength; }, 0);
    var all = entries.concat(dirs).concat([eocdRec(dirs.length, cdSz, off)]);
    var total = all.reduce(function (s, b) { return s + b.byteLength; }, 0);
    var out = new Uint8Array(total), pos = 0;
    all.forEach(function (b) { out.set(b, pos); pos += b.byteLength; });
    return out.buffer;
  }

  function u16(v) { return new Uint8Array([v & 0xFF, (v >> 8) & 0xFF]); }
  function u32(v) { return new Uint8Array([v & 0xFF, (v >> 8) & 0xFF, (v >> 16) & 0xFF, (v >>> 24) & 0xFF]); }
  function cat(parts) {
    var total = parts.reduce(function (s, a) { return s + a.byteLength; }, 0);
    var out = new Uint8Array(total), pos = 0;
    parts.forEach(function (a) { out.set(a, pos); pos += a.byteLength; });
    return out;
  }
  function lhdr(nb, sz, crc) {
    return cat([new Uint8Array([0x50,0x4B,0x03,0x04]), u16(20), u16(0), u16(0), u16(0), u16(0x4A21),
      u32(crc), u32(sz), u32(sz), u16(nb.byteLength), u16(0), nb]);
  }
  function cdir(nb, sz, crc, off) {
    return cat([new Uint8Array([0x50,0x4B,0x01,0x02]), u16(20), u16(20), u16(0), u16(0), u16(0), u16(0x4A21),
      u32(crc), u32(sz), u32(sz), u16(nb.byteLength), u16(0), u16(0), u16(0), u16(0), u32(0), u32(off), nb]);
  }
  function eocdRec(cnt, cdSz, cdOff) {
    return cat([new Uint8Array([0x50,0x4B,0x05,0x06]), u16(0), u16(0), u16(cnt), u16(cnt),
      u32(cdSz), u32(cdOff), u16(0)]);
  }
  function crc32b(buf) {
    if (!crc32b._t) {
      crc32b._t = new Uint32Array(256);
      for (var i = 0; i < 256; i++) { var c = i; for (var j = 0; j < 8; j++) c = (c & 1) ? 0xEDB88320 ^ (c >>> 1) : c >>> 1; crc32b._t[i] = c; }
    }
    var crc = 0xFFFFFFFF, t = crc32b._t;
    for (var i = 0; i < buf.byteLength; i++) crc = t[(crc ^ buf[i]) & 0xFF] ^ (crc >>> 8);
    return (crc ^ 0xFFFFFFFF) >>> 0;
  }

  function writeFile(wb, filename) {
    var zip = buildZip(wb);
    var blob = new Blob([zip], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = filename;
    document.body.appendChild(a); a.click();
    setTimeout(function () { document.body.removeChild(a); URL.revokeObjectURL(url); }, 300);
  }

  return {
    utils: { book_new: book_new, book_append_sheet: book_append_sheet, json_to_sheet: json_to_sheet, aoa_to_sheet: aoa_to_sheet, decode_range: decode_range, encode_cell: encode_cell },
    writeFile: writeFile
  };
})();
